    expect(calculateTax(1)).toBe(0);
  });

  it("AC1: returns 0 for income of $9,999.99 (floating-point just below threshold)", () => {
    expect(calculateTax(9_999.99)).toBe(0);
  });

  // ── AC2: income = $10,000 → tax = income * 0.10 ──────────────────────────
  it("AC2: returns income * 0.10 for income of exactly $10,000 (bracket starts inclusive)", () => {
    expect(calculateTax(10_000)).toBe(1_000);
  });

  // ── AC3: income $10,001–$50,000 → tax = income * 0.10 ───────────────────
  it("AC3: returns income * 0.10 for income of $10,001 (just above lower boundary)", () => {
    expect(calculateTax(10_001)).toBeCloseTo(1_000.1, 5);
  });

  it("AC3: returns income * 0.10 for income of $30,000 (mid bracket)", () => {
    expect(calculateTax(30_000)).toBe(3_000);
  });

  // ── AC4: income = $50,000 → tax = income * 0.10 (25% starts at $50,001) ─
  it("AC4: returns income * 0.10 for income of exactly $50,000 (still 10% bracket)", () => {
    expect(calculateTax(50_000)).toBe(5_000);
  });

  // ── AC5: income $50,001–$150,000 → tax = income * 0.25 ──────────────────
